import { existsSync, mkdirSync, readdirSync, readFileSync, rmSync, writeFileSync } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";
import { FUNCTION_ROUTES } from "../src/server/function-routes.js";

const ROOT_DIR = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const GENERATED_HEADER = [
  "/* eslint-disable */",
  "// This file is auto-generated by scripts/generate-function-wrappers.mjs.",
  "// Do not edit it by hand.",
  "",
].join("\n");
const GENERATED_SENTINEL = "This file is auto-generated by scripts/generate-function-wrappers.mjs.";
const OUTPUT_DIRECTORIES = {
  vercel: path.join("src", "pages", "api"),
  cloudflare: path.join("functions", "api"),
  edgeone: path.join("cloud-functions", "api"),
};
const OUTPUT_ROOT_DIRECTORIES = {
  vercel: path.join("src", "pages", "api"),
  cloudflare: path.join("functions"),
  edgeone: path.join("cloud-functions"),
};
const LEGACY_OUTPUT_ROOT_DIRECTORIES = [
  path.join("api"),
];

function renderSharedImports(route, methods, importPath, options = {}) {
  const aliases = methods.map((method) => {
    if (method === "OPTIONS") {
      return `${method} as SHARED_OPTIONS`;
    }

    return method;
  });

  return `${GENERATED_HEADER}import { ${options.dispatchImport} } from "${options.dispatchPath}";
import { ${aliases.join(", ")} } from "${importPath}";

const handlers = {
${methods.map((method) => `  ${method}: ${method === "OPTIONS" ? "SHARED_OPTIONS" : method},`).join("\n")}
};
`;
}

function renderVercelWrapper({ handlerModule, methods }) {
  const handlerImports = methods.map((method) => {
    if (method === "OPTIONS") {
      return `${method} as SHARED_OPTIONS`;
    }

    return `${method} as SHARED_${method}`;
  });

  const routeHandlers = methods.map((method) => {
    if (method === "OPTIONS") {
      return `export function OPTIONS() {
  setRuntimeDeployTarget("vercel");
  return SHARED_OPTIONS();
}`;
    }

    return `export function ${method}(context: Parameters<typeof SHARED_${method}>[0]) {
  setRuntimeDeployTarget("vercel");
  return SHARED_${method}(context);
}`;
  });

  const handlerImportPath = `../../${handlerModule.replace(/^src\//, "")}.js`;

  return `${GENERATED_HEADER}import { setRuntimeDeployTarget } from "../../platform/shared/target.js";
import { ${handlerImports.join(", ")} } from "${handlerImportPath}";

export const prerender = false;

${routeHandlers.join("\n\n")}
`;
}

function renderEdgeRuntimeWrapper(target, { handlerModule, methods }) {
  const base = renderSharedImports(
    handlerModule,
    methods,
    `../../${handlerModule}.js`,
    {
      dispatchImport: "dispatchFunctionRequest",
      dispatchPath: "../../src/server/function-dispatch.js",
    },
  );

  const runtimeFunctions = [
    `export function onRequestGet(context: { request: Request }) {
  return dispatchFunctionRequest("${target}", context.request, handlers);
}`,
    `export function onRequestOptions(context: { request: Request }) {
  return dispatchFunctionRequest("${target}", context.request, handlers);
}`,
  ];

  return `${base}
${runtimeFunctions.join("\n\n")}
`;
}

function writeGeneratedFile(rootDir, relativePath, content) {
  const fullPath = path.join(rootDir, relativePath);
  mkdirSync(path.dirname(fullPath), { recursive: true });
  writeFileSync(fullPath, content, "utf8");
}

function removeGeneratedWrappers(directoryPath) {
  if (!existsSync(directoryPath)) {
    return;
  }

  for (const entry of readdirSync(directoryPath, { withFileTypes: true })) {
    if (!entry.isFile() || path.extname(entry.name) !== ".ts") {
      continue;
    }

    const filePath = path.join(directoryPath, entry.name);
    const source = readFileSync(filePath, "utf8");
    if (source.includes(GENERATED_SENTINEL)) {
      rmSync(filePath, { force: true });
    }
  }

  if (readdirSync(directoryPath).length === 0) {
    rmSync(directoryPath, { recursive: true, force: true });
  }
}

function resolveTargets(target) {
  if (!target || target === "all") {
    return Object.keys(OUTPUT_DIRECTORIES);
  }

  if (target in OUTPUT_DIRECTORIES) {
    return [target];
  }

  throw new Error(`Unsupported function wrapper target "${target}"`);
}

function renderWrapperForTarget(target, routeConfig) {
  if (target === "vercel") {
    return renderVercelWrapper(routeConfig);
  }

  return renderEdgeRuntimeWrapper(target, routeConfig);
}

export function generateFunctionWrappers({ rootDir = ROOT_DIR, target = "all" } = {}) {
  const targets = resolveTargets(target);

  for (const relativeRoot of LEGACY_OUTPUT_ROOT_DIRECTORIES) {
    removeGeneratedWrappers(path.join(rootDir, relativeRoot));
  }

  for (const [targetName, relativeRoot] of Object.entries(OUTPUT_ROOT_DIRECTORIES)) {
    if (targetName === "vercel") {
      removeGeneratedWrappers(path.join(rootDir, relativeRoot));
      continue;
    }

    rmSync(path.join(rootDir, relativeRoot), { recursive: true, force: true });
  }

  for (const targetName of targets) {
    for (const routeConfig of FUNCTION_ROUTES) {
      writeGeneratedFile(
        rootDir,
        path.join(OUTPUT_DIRECTORIES[targetName], `${routeConfig.route}.ts`),
        renderWrapperForTarget(targetName, routeConfig),
      );
    }
  }
}

if (process.argv[1] === fileURLToPath(import.meta.url)) {
  generateFunctionWrappers({ target: process.argv[2] || "all" });
}
